  for (const key of ["roundingStep", "fixedFeeVnd", "variableFeeRate", "paymentFeeRate", "serviceFeeRate", "shippingSupportVnd", "voucherPercent", "voucherFixedVnd", "returnReserveRate", "affiliateRate", "adsCostVnd", "taxRate", "targetMarginRate", "minimumProfitVnd"]) if (salesOverrides[key] != null && salesOverrides[key] !== "") salesOverrides[key] = Math.max(0, num(salesOverrides[key]));
  return { id: source.id || uid(), name: String(source.name || "Mẫu mới").trim(), image: /^data:image\/(jpeg|png|webp|gif);base64,/i.test(source.image || "") ? source.image : "", rounding: Math.max(1, num(source.rounding, 1000)), targetPrice: Math.max(0, num(source.targetPrice)), salesProfileId: source.salesProfileId || source.defaultProfileId || source.profileId || "", salesOverrides, saleScenario, costing: { ...costing, machineValue: Math.max(0, num(costing.machineValue)), machineLifetimeHours: Math.max(1, num(costing.machineLifetimeHours, 1)), powerKw: Math.max(0, num(costing.powerKw)), electricityRate: Math.max(0, num(costing.electricityRate)), maintenancePerHour: Math.max(0, num(costing.maintenancePerHour)), consumablePerHour: Math.max(0, num(costing.consumablePerHour)), laborHours: Math.max(0, num(costing.laborHours)), laborRate: Math.max(0, num(costing.laborRate)), materialWasteRate: Math.max(0, num(costing.materialWasteRate)), printFailureRate: Math.max(0, num(costing.printFailureRate)), finishingWasteRate: Math.max(0, num(costing.finishingWasteRate)), designCostVnd: Math.max(0, num(costing.designCostVnd)), stlLicenseVnd: Math.max(0, num(costing.stlLicenseVnd)), sampleCostVnd: Math.max(0, num(costing.sampleCostVnd)), photoCostVnd: Math.max(0, num(costing.photoCostVnd)), otherProductionVnd: Math.max(0, num(costing.otherProductionVnd)), packagingCostVnd: Math.max(0, num(costing.packagingCostVnd)), shippingSupportVnd: Math.max(0, num(costing.shippingSupportVnd)), orderProcessingFeeVnd: Math.max(0, num(costing.orderProcessingFeeVnd)), codFeeVnd: Math.max(0, num(costing.codFeeVnd)), voucherShopFixedVnd: Math.max(0, num(costing.voucherShopFixedVnd)), giftCostVnd: Math.max(0, num(costing.giftCostVnd)), returnReserveVnd: Math.max(0, num(costing.returnReserveVnd)), otherFixedOrderVnd: Math.max(0, num(costing.otherFixedOrderVnd)), batchQty: Math.max(1, num(costing.batchQty, 1)), batchSetupCostVnd: Math.max(0, num(costing.batchSetupCostVnd)), batchPurgeGrams: Math.max(0, num(costing.batchPurgeGrams)), batchSetupHours: Math.max(0, num(costing.batchSetupHours)), batchExpectedSalesQty: Math.max(1, num(costing.batchExpectedSalesQty, 1)) }, listing: { title: String(source.listing?.title ?? source.name ?? "").trim(), description: String(source.listing?.description ?? "").trim() }, batch: { batchQty: Math.max(1, num(source.batch?.batchQty ?? costing.batchQty, 1)), batchSetupCostVnd: Math.max(0, num(source.batch?.batchSetupCostVnd ?? costing.batchSetupCostVnd)), batchPurgeGrams: Math.max(0, num(source.batch?.batchPurgeGrams ?? costing.batchPurgeGrams)), batchSetupHours: Math.max(0, num(source.batch?.batchSetupHours ?? costing.batchSetupHours)), batchExpectedSalesQty: Math.max(1, num(source.batch?.batchExpectedSalesQty ?? costing.batchExpectedSalesQty, 1)) }, components: Array.isArray(source.components) ? source.components.map(c => ({ id: c.id || uid(), name: String(c.name || "Cấu phần mới"), materialId: c.materialId || "", quantity: Math.max(0, num(c.quantity)), printHours: Math.max(0, num(c.printHours)) })) : [] };
