function rememberTemplateDefaults(product) { state.templateDefaults = { costing: clone(product.costing), salesProfileId: product.salesProfileId || state.templateDefaults?.salesProfileId || state.salesProfiles[0]?.id || "", rounding: Math.max(1, num(product.rounding, 1000)) }; }
function compressImage(file) { return new Promise((resolve, reject) => { const reader = new FileReader(); reader.onerror = reject; reader.onload = () => { const img = new Image(); img.onerror = reject; img.onload = () => { const max = 720; const scale = Math.min(1, max / Math.max(img.width, img.height)); const canvas = document.createElement("canvas"); canvas.width = Math.round(img.width * scale); canvas.height = Math.round(img.height * scale); const ctx = canvas.getContext("2d"); ctx.fillStyle = "#fff"; ctx.fillRect(0, 0, canvas.width, canvas.height); ctx.drawImage(img, 0, 0, canvas.width, canvas.height); resolve(canvas.toDataURL("image/jpeg", 0.72)); }; img.src = reader.result; }; reader.readAsDataURL(file); }); }
function unitPrice(material) { return material && material.quantity ? material.cost / material.quantity : 0; }
function materialById(id) { return state.materials.find(m => m.id === id); }
function componentCost(component) { const material = materialById(component.materialId); return unitPrice(material) * num(component.quantity); }
function machineHourlyRate(product) { const c = product.costing; const lifetime = Math.max(1, num(c.machineLifetimeHours, 1)); return num(c.machineValue) / lifetime; }
function productPrintHours(product) { return product.components.reduce((sum, c) => sum + num(c.printHours), 0); }
