function productRow(product, index) { const pricing = productionAndPricing(product, resolveSalesSettings(product)); return `<div class="product-row" data-product-id="${product.id}"><span class="product-avatar ${product.image ? "has-image" : ""}">${productVisual(product, String(index + 1).padStart(2, "0"))}</span><div class="product-name"><strong>${escapeHtml(product.name)}</strong><small>${product.components.length} cấu phần · ${number(productPrintHours(product))} giờ máy</small></div><div class="cost-cell"><span class="cell-label">Giá vốn</span><span class="money">${money(pricing.breakdown.productionTotal + pricing.fixedOrder)}</span></div><div class="optional-cell"><span class="cell-label">Giá an toàn</span><span class="money">${money(pricing.roundedSafePrice || 0)}</span></div><span class="price-tag">${product.targetPrice ? compactMoney(product.targetPrice) : "Chưa chốt"}</span></div>`; }
function renderDashboard() { const products = [...state.products].sort((a, b) => priceForProduct(b) - priceForProduct(a)); const avg = products.length ? products.reduce((s, p) => s + (priceForProduct(p) || 0), 0) / products.length : 0; const topMaterials = [...state.materials].sort((a, b) => b.cost - a.cost).slice(0, 4); const max = topMaterials[0]?.cost || 1; $("#dashboardView").innerHTML = `${pageHeading("BẢNG ĐIỀU KHIỂN", "Chào xưởng, hôm nay tính gì?", "Mọi con số được cập nhật trực tiếp từ kho vật tư, profile kênh bán và định mức sản phẩm.")}<div class="kpi-grid"><article class="kpi-card accent"><span class="kpi-label">Tổng vốn đã nhập</span><strong class="kpi-value">${compactMoney(totalInvestment())}</strong><span class="kpi-meta">${state.materials.length} vật tư · ${state.salesProfiles.length} profile</span></article><article class="kpi-card"><span class="kpi-label">Mẫu sản phẩm</span><strong class="kpi-value">${state.products.length}</strong><span class="kpi-meta">Chọn mẫu để xem giá theo kênh</span></article><article class="kpi-card"><span class="kpi-label">Giá bán gợi ý TB</span><strong class="kpi-value">${compactMoney(avg)}</strong><span class="kpi-meta">Đã gồm phí và margin theo profile</span></article><article class="kpi-card"><span class="kpi-label">Vật tư lớn nhất</span><strong class="kpi-value">${compactMoney(topMaterials[0]?.cost || 0)}</strong><span class="kpi-meta">${escapeHtml(topMaterials[0]?.name || "Chưa có")}</span></article></div><div class="dashboard-grid"><article class="panel"><div class="panel-head"><h3>Mẫu sản phẩm gần đây</h3><button class="link-button" data-go="products">Xem tất cả</button></div><div>${products.slice(0, 5).map((p, i) => productRow(p, i)).join("") || `<div class="empty-state">Chưa có mẫu nào.</div>`}</div></article><article class="panel"><div class="panel-head"><h3>Khoản đầu tư lớn</h3><button class="link-button" data-go="materials">Mở kho</button></div><div class="material-bars">${topMaterials.map(m => `<div class="bar-item"><div class="bar-item-head"><span>${escapeHtml(m.name)}</span><strong>${compactMoney(m.cost)}</strong></div><div class="bar-track"><div class="bar-fill" style="width:${Math.max(5, m.cost / max * 100)}%"></div></div></div>`).join("")}</div></article></div>`; }
function warningPills(warnings) { if (!warnings.length) return `<div class="summary-note success">Không có cảnh báo.</div>`; return `<div class="warning-stack">${warnings.map(w => `<div class="warning-item">⚠ ${escapeHtml(w)}</div>`).join("")}</div>`; }
function renderChannelCards(product) { return state.salesProfiles.map(profile => { const calc = productionAndPricing(product, resolveSalesSettings(product, profile)); return `<article class="channel-card"><div class="channel-card-head"><div><strong>${escapeHtml(profile.name)}</strong><small>${escapeHtml(profile.note || "Không có ghi chú")}</small></div><span class="status-chip">${money(calc.roundedSafePrice || 0)}</span></div><div class="channel-card-grid"><div><span>Hòa vốn</span><strong>${money(calc.breakevenPrice || 0)}</strong></div><div><span>Giá an toàn</span><strong>${money(calc.roundedSafePrice || 0)}</strong></div><div><span>Giá sale thấp nhất</span><strong>${money(calc.minNoLossSale || 0)}</strong></div><div><span>Niêm yết đề xuất</span><strong>${money(calc.suggestedListing || 0)}</strong></div><div><span>Phí dự kiến</span><strong>${money(calc.fixedOrder + (calc.suggestedListing || 0) * calc.rVariable)}</strong></div><div><span>Lợi nhuận dự kiến</span><strong>${money((calc.suggestedListing || 0) * (1 - calc.rVariable) - calc.fixedOrder - calc.breakdown.productionTotal)}</strong></div><div><span>Margin dự kiến</span><strong>${number((calc.suggestedListing || 0) ? (((calc.suggestedListing || 0) * (1 - calc.rVariable) - calc.fixedOrder - calc.breakdown.productionTotal) / (calc.suggestedListing || 1)) * 100 : 0)}%</strong></div><div><span>Step</span><strong>${money(resolveSalesSettings(product, profile).roundingStep)}</strong></div></div></article>`; }).join(""); }
function renderEditor() { const p = state.products.find(x => x.id === currentProductId); if (!p) { navigate("products"); return; } const settings = resolveSalesSettings(p); const pricing = productionAndPricing(p, settings); const sale = saleScenarioResult(p, settings, p.saleScenario); const status = targetPriceStatus(p, settings); const profileSelect = state.salesProfiles.map(pr => `<option value="${pr.id}" ${pr.id === p.salesProfileId ? "selected" : ""}>${escapeHtml(pr.name)}</option>`).join(""); const warnings = [...pricing.warnings, ...sale.warnings]; const manualDiff = num(p.targetPrice) - (pricing.roundedSafePrice || pricing.breakevenPrice || 0); const manualProfit = num(p.targetPrice) * (1 - pricing.rVariable) - pricing.fixedOrder - pricing.breakdown.productionTotal; const manualMargin = num(p.targetPrice) > 0 ? manualProfit / num(p.targetPrice) * 100 : 0; $("#editorView").innerHTML = `${pageHeading("CHỈNH ĐỊNH MỨC", "Giá bán thực chiến cho xưởng in 3D", "Tách riêng giá vốn, giá hòa vốn, giá sale và lãi ròng thực nhận.", `<button class="secondary-button" data-back-products>← Trở lại</button>`)}<div class="editor-layout"><div class="editor-main"><div class="editor-head"><div class="editor-title-wrap"><div class="editor-thumb ${p.image ? "has-image" : ""}">${productVisual(p, "◇")}</div><div><input class="title-input" id="productName" value="${escapeAttr(p.name)}" /><p>${p.components.length} cấu phần · ${number(productPrintHours(p))} giờ máy · tự lưu</p></div></div><div class="editor-head-actions"><label class="image-upload-button">▣ Ảnh sản phẩm<input id="productImageInput" type="file" accept="image/*" hidden /></label>${p.image ? `<button class="icon-button" data-remove-image title="Xoá ảnh">×</button>` : ""}<button class="icon-button" data-duplicate="${p.id}" title="Nhân bản">⧉</button><button class="icon-button" data-delete-product="${p.id}" title="Xoá mẫu">⌫</button></div></div><div class="bom-head"><span>Tên cấu phần</span><span>Vật tư sử dụng</span><span>Lượng dùng</span><span>Giờ máy</span><span style="text-align:right">Chi phí trực tiếp</span><span></span></div><div id="bomRows">${p.components.map(x => bomRow(p, x)).join("")}</div><button class="add-row" data-add-component>＋ Thêm cấu phần</button><section class="cost-settings"><div class="cost-settings-head"><div><span class="eyebrow">THÔNG SỐ SẢN XUẤT</span><h3>Giá vốn, hao hụt và chi phí phân bổ</h3></div><p>Thông số nâng cao nằm trong accordion để giữ giao diện gọn.</p></div><details class="advanced-box" open><summary>Giá vốn sản xuất</summary><div class="settings-grid four"><label>Khấu hao máy / giờ<input data-cost-field="machineValue" type="number" min="0" step="100000" value="${p.costing.machineValue}"><small>Giá mua máy và nâng cấp</small></label><label>Vòng đời máy (giờ)<input data-cost-field="machineLifetimeHours" type="number" min="1" step="100" value="${p.costing.machineLifetimeHours}"><small>Khấu hao hiện tại: ${money(machineHourlyRate(p))}/giờ</small></label><label>Công suất máy (kW)<input data-cost-field="powerKw" type="number" min="0" step="0.01" value="${p.costing.powerKw}"><small>120W = 0,12 kW</small></label><label>Điện / kWh<input data-cost-field="electricityRate" type="number" min="0" step="100" value="${p.costing.electricityRate}"><small>Tra theo hoá đơn điện thực tế</small></label><label>Bảo trì / giờ in<input data-cost-field="maintenancePerHour" type="number" min="0" step="100" value="${p.costing.maintenancePerHour}"><small>Dầu, nozzle, bảo dưỡng</small></label><label>Vật tư tiêu hao / giờ<input data-cost-field="consumablePerHour" type="number" min="0" step="100" value="${p.costing.consumablePerHour}"><small>Nozzle, PTFE, keo bàn in...</small></label><label>Nhân công hoàn thiện (giờ)<input data-cost-field="laborHours" type="number" min="0" step="0.1" value="${p.costing.laborHours}"></label><label>Nhân công / giờ<input data-cost-field="laborRate" type="number" min="0" step="1000" value="${p.costing.laborRate}"></label><label>Thiết kế / mua file<input data-cost-field="designCostVnd" type="number" min="0" step="1000" value="${p.costing.designCostVnd}"></label><label>Commercial license / STL<input data-cost-field="stlLicenseVnd" type="number" min="0" step="1000" value="${p.costing.stlLicenseVnd}"></label><label>Chi phí thử mẫu<input data-cost-field="sampleCostVnd" type="number" min="0" step="1000" value="${p.costing.sampleCostVnd}"></label><label>Ảnh / content<input data-cost-field="photoCostVnd" type="number" min="0" step="1000" value="${p.costing.photoCostVnd}"></label><label>Chi phí khác<input data-cost-field="otherProductionVnd" type="number" min="0" step="1000" value="${p.costing.otherProductionVnd}"></label><label>Hao hụt nhựa in (%)<input data-cost-field="materialWasteRate" type="number" min="0" step="0.1" value="${p.costing.materialWasteRate}"><small>Chỉ cho print_material</small></label><label>Dự phòng in lỗi (%)<input data-cost-field="printFailureRate" type="number" min="0" step="0.1" value="${p.costing.printFailureRate}"><small>Áp cho nhựa + máy + điện</small></label><label>Hao hụt hoàn thiện (%)<input data-cost-field="finishingWasteRate" type="number" min="0" step="0.1" value="${p.costing.finishingWasteRate}"><small>Chỉ cho finishing_supply</small></label></div></details><details class="advanced-box"><summary>Tối ưu khi in theo lô</summary><div class="settings-grid four"><label>Số lượng trong lô<input data-batch-field="batchQty" type="number" min="1" step="1" value="${p.batch.batchQty}"></label><label>Chi phí setup đầu job<input data-batch-field="batchSetupCostVnd" type="number" min="0" step="1000" value="${p.batch.batchSetupCostVnd}"></label><label>Gram purge/setup<input data-batch-field="batchPurgeGrams" type="number" min="0" step="1" value="${p.batch.batchPurgeGrams}"></label><label>Giờ setup<input data-batch-field="batchSetupHours" type="number" min="0" step="0.1" value="${p.batch.batchSetupHours}"></label><label>Số lượng dự kiến bán<input data-batch-field="batchExpectedSalesQty" type="number" min="1" step="1" value="${p.batch.batchExpectedSalesQty}"></label></div></details><details class="advanced-box"><summary>Chi phí theo đơn hàng</summary><div class="settings-grid four"><label>Đóng gói<input data-cost-field="packagingCostVnd" type="number" min="0" step="1000" value="${p.costing.packagingCostVnd}"></label><label>Hỗ trợ ship (sản phẩm)<input data-cost-field="shippingSupportVnd" type="number" min="0" step="1000" value="${p.costing.shippingSupportVnd}"></label><label>Phí xử lý đơn<input data-cost-field="orderProcessingFeeVnd" type="number" min="0" step="1000" value="${p.costing.orderProcessingFeeVnd}"></label><label>Phí COD<input data-cost-field="codFeeVnd" type="number" min="0" step="1000" value="${p.costing.codFeeVnd}"></label><label>Voucher shop chịu (₫)<input data-cost-field="voucherShopFixedVnd" type="number" min="0" step="1000" value="${p.costing.voucherShopFixedVnd}"></label><label>Quà tặng kèm<input data-cost-field="giftCostVnd" type="number" min="0" step="1000" value="${p.costing.giftCostVnd}"></label><label>Dự phòng đổi trả<input data-cost-field="returnReserveVnd" type="number" min="0" step="1000" value="${p.costing.returnReserveVnd}"></label><label>Phụ phí khác<input data-cost-field="otherFixedOrderVnd" type="number" min="0" step="1000" value="${p.costing.otherFixedOrderVnd}"></label></div></details><details class="advanced-box"><summary>Kênh bán mặc định & ghi đè nhanh</summary><div class="settings-grid four"><label>Kênh bán mặc định<select id="productSalesProfileId">${profileSelect}</select></label><label>Bước làm tròn giá<input id="roundingInput" type="number" min="1" step="100" value="${p.rounding}"><small>${money(settings.roundingStep)} / bước</small></label><label>Phí cố định mỗi đơn<input data-sales-override="fixedFeeVnd" type="number" min="0" step="1000" value="${p.salesOverrides.fixedFeeVnd ?? ""}" placeholder="${money(settings.fixedFeeVnd)}"></label><label>Phí tỷ lệ doanh thu (%)<input data-sales-override="variableFeeRate" type="number" min="0" step="0.1" value="${p.salesOverrides.variableFeeRate ?? ""}" placeholder="${number(settings.variableFeeRate)}"></label><label>Phí thanh toán (%)<input data-sales-override="paymentFeeRate" type="number" min="0" step="0.1" value="${p.salesOverrides.paymentFeeRate ?? ""}" placeholder="${number(settings.paymentFeeRate)}"></label><label>Phí dịch vụ (%)<input data-sales-override="serviceFeeRate" type="number" min="0" step="0.1" value="${p.salesOverrides.serviceFeeRate ?? ""}" placeholder="${number(settings.serviceFeeRate)}"></label><label>Affiliate/KOC (%)<input data-sales-override="affiliateRate" type="number" min="0" step="0.1" value="${p.salesOverrides.affiliateRate ?? ""}" placeholder="${number(settings.affiliateRate)}"></label><label>Thuế/khấu trừ (%)<input data-sales-override="taxRate" type="number" min="0" step="0.1" value="${p.salesOverrides.taxRate ?? ""}" placeholder="${number(settings.taxRate)}"></label><label>Margin mục tiêu (%)<input data-sales-override="targetMarginRate" type="number" min="0" max="90" step="0.1" value="${p.salesOverrides.targetMarginRate ?? ""}" placeholder="${number(settings.targetMarginRate)}"></label><label>Lợi nhuận tối thiểu (₫)<input data-sales-override="minimumProfitVnd" type="number" min="0" step="1000" value="${p.salesOverrides.minimumProfitVnd ?? ""}" placeholder="${money(settings.minimumProfitVnd)}"></label><label>Voucher %<input data-sales-override="voucherPercent" type="number" min="0" max="100" step="0.1" value="${p.salesOverrides.voucherPercent ?? ""}" placeholder="${number(settings.voucherPercent)}"></label><label>Voucher tiền<input data-sales-override="voucherFixedVnd" type="number" min="0" step="1000" value="${p.salesOverrides.voucherFixedVnd ?? ""}" placeholder="${money(settings.voucherFixedVnd)}"></label><label>Ads / đơn<input data-sales-override="adsCostVnd" type="number" min="0" step="1000" value="${p.salesOverrides.adsCostVnd ?? ""}" placeholder="${money(settings.adsCostVnd)}"></label><label>Hỗ trợ ship kênh<input data-sales-override="shippingSupportVnd" type="number" min="0" step="1000" value="${p.salesOverrides.shippingSupportVnd ?? ""}" placeholder="${money(settings.shippingSupportVnd)}"></label><label>Dự phòng hoàn hàng (%)<input data-sales-override="returnReserveRate" type="number" min="0" step="0.1" value="${p.salesOverrides.returnReserveRate ?? ""}" placeholder="${number(settings.returnReserveRate)}"></label></div></details></section><section class="listing-section"><div class="listing-head"><div><span class="eyebrow">NỘI DUNG ĐĂNG BÁN</span><h3>Dành cho cộng tác viên</h3></div><p>Chỉnh nội dung một lần, cộng tác viên chỉ việc bấm sao chép và đăng bài.</p></div><div class="listing-copy-grid"><div class="copy-field price-copy"><label>Giá đăng bán</label><div><input id="copySalePrice" readonly value="${escapeAttr(money(p.targetPrice || pricing.roundedSafePrice || 0))}"><button type="button" data-copy-target="#copySalePrice">Sao chép</button></div></div><div class="copy-field"><label>Tiêu đề mẫu</label><div><input id="copyListingTitle" data-listing-field="title" value="${escapeAttr(p.listing.title)}" placeholder="Ví dụ: Đèn ngủ in 3D phong cách hiện đại"><button type="button" data-copy-target="#copyListingTitle">Sao chép</button></div></div><div class="copy-field description-copy"><label>Mô tả mẫu</label><div><textarea id="copyListingDescription" data-listing-field="description" rows="7" placeholder="Nhập mô tả sản phẩm, kích thước, màu sắc, tình trạng và cách liên hệ...">${escapeHtml(p.listing.description)}</textarea><button type="button" data-copy-target="#copyListingDescription">Sao chép</button></div></div></div></section></div><aside class="summary-card"><div class="summary-header"><h3>Cảnh báo & kết quả</h3><span class="status-pill ${warnings.length ? "danger" : "success"}">${warnings.length ? `${warnings.length} cảnh báo` : "Ổn"}</span></div>${warningPills(warnings)}<section class="summary-block"><h4>Giá vốn sản xuất</h4><div class="summary-line"><span>Nhựa in</span><strong>${money(pricing.breakdown.materialBreakdown.print_material)}</strong></div><div class="summary-line"><span>Linh kiện mua ngoài</span><strong>${money(pricing.breakdown.materialBreakdown.purchased_component)}</strong></div><div class="summary-line"><span>Vật tư hoàn thiện</span><strong>${money(pricing.breakdown.materialBreakdown.finishing_supply)}</strong></div><div class="summary-line"><span>Tiêu hao</span><strong>${money(pricing.breakdown.materialBreakdown.consumable)}</strong></div><div class="summary-line"><span>Hao hụt nhựa</span><strong>${money(pricing.breakdown.wasteMaterial)}</strong></div><div class="summary-line"><span>Dự phòng in lỗi</span><strong>${money(pricing.breakdown.printFailure)}</strong></div><div class="summary-line"><span>Khấu hao máy</span><strong>${money(pricing.breakdown.machine)}</strong></div><div class="summary-line"><span>Điện năng</span><strong>${money(pricing.breakdown.electricity)}</strong></div><div class="summary-line"><span>Bảo trì</span><strong>${money(pricing.breakdown.maintenance)}</strong></div><div class="summary-line"><span>Nhân công</span><strong>${money(pricing.breakdown.labor)}</strong></div><div class="summary-line"><span>Thiết kế / license</span><strong>${money(pricing.breakdown.directProduction)}</strong></div><div class="summary-line"><span>Setup lô</span><strong>${money(pricing.breakdown.batchSetup)}</strong></div><div class="summary-line total-line"><span>Tổng giá vốn</span><strong>${money(pricing.breakdown.productionTotal)}</strong></div></section><section class="summary-block"><h4>Kịch bản sale</h4><label class="target-price-label">Giá niêm yết<input id="saleListingPrice" type="number" min="0" step="1000" value="${sale.listingPrice || pricing.suggestedListing || pricing.roundedSafePrice || 0}" /></label><div class="summary-controls"><label>Voucher %<input id="saleVoucherPercent" type="number" min="0" max="100" step="0.1" value="${sale.voucherPercent ?? 0}" /></label><label>Voucher tiền<input id="saleVoucherFixedVnd" type="number" min="0" step="1000" value="${sale.voucherFixedVnd ?? 0}" /></label></div><div class="summary-line"><span>Giá khách thực trả</span><strong>${money(sale.saleActual)}</strong></div><div class="summary-line"><span>Shop thực nhận sau phí</span><strong>${money(sale.saleActual * (1 - pricing.rVariable) - pricing.fixedOrder)}</strong></div><div class="summary-line"><span>Lợi nhuận ròng</span><strong>${money(sale.net)}</strong></div><div class="summary-line"><span>Margin thực tế</span><strong>${number(sale.margin * 100)}%</strong></div><div class="summary-line"><span>Giá sale thấp nhất không lỗ</span><strong>${money(sale.minNoLossSale || 0)}</strong></div><div class="summary-line"><span>Giá sale đạt mục tiêu</span><strong>${money(sale.minTargetSale || 0)}</strong></div><div class="summary-line"><span>Gợi ý niêm yết có voucher</span><strong>${money(sale.recommendedListing || 0)}</strong></div></section><section class="summary-block"><h4>Giá theo kênh bán</h4><div class="channel-stack">${renderChannelCards(p)}</div></section><section class="summary-block"><h4>Giá chốt thủ công</h4><label class="target-price-label">Giá bán bạn chốt<input id="targetPriceInput" type="number" min="0" step="1000" value="${p.targetPrice || 0}" /></label><div class="summary-line"><span>Shop thực nhận sau phí</span><strong>${money(num(p.targetPrice) * (1 - pricing.rVariable) - pricing.fixedOrder)}</strong></div><div class="summary-line"><span>Lãi/lỗ ròng</span><strong>${money(manualProfit)}</strong></div><div class="summary-line"><span>Margin thực tế</span><strong>${number(manualMargin)}%</strong></div><div class="summary-line"><span>Chênh lệch so với giá an toàn</span><strong>${money(manualDiff)}</strong></div><div class="status-line ${status.tone}">${status.label} · ${escapeHtml(status.note)}</div><p class="profit-note">${manualProfit >= 0 ? `Đang lãi <strong>${money(manualProfit)}</strong>.` : `Đang lỗ <strong class="negative">${money(Math.abs(manualProfit))}</strong>.`}</p></section></aside></div>`; }
function renderMaterials(filter = "") { const list = state.materials.filter(m => [m.name, m.unit, m.note, m.category, m.supplier].join(" ").toLowerCase().includes(filter.toLowerCase())); $("#materialsView").innerHTML = `${pageHeading("DANH MỤC GỐC", "Kho vật tư", "Cập nhật một lần, mọi mẫu dùng vật tư đó sẽ tự tính lại.", `<button class="primary-button" data-add-material>＋ Thêm vật tư</button>`)}<div class="section-toolbar"><div class="search-wrap"><input id="materialSearch" value="${escapeAttr(filter)}" placeholder="Tìm vật tư, đơn vị, ghi chú..." /></div><span class="date-chip">${list.length} vật tư</span></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Hạng mục</th><th>Category</th><th class="number">Tổng chi phí</th><th class="number">Số lượng</th><th>Đơn vị</th><th class="number">Đơn giá / 1</th><th>Nhà cung cấp</th><th></th></tr></thead><tbody>${list.map(m => `<tr><td class="material-name"><strong>${escapeHtml(m.name)}</strong>${m.note ? `<small>${escapeHtml(m.note)}</small>` : ""}</td><td><span class="status-pill">${CATEGORY_LABELS[m.category] || m.category}</span></td><td class="number">${money(m.cost)}</td><td class="number">${number(m.quantity)}</td><td>${escapeHtml(m.unit)}</td><td class="number"><strong>${money(unitPrice(m))}</strong></td><td>${escapeHtml(m.supplier || "")}${m.lastPurchasedAt ? `<small>${escapeHtml(m.lastPurchasedAt)}</small>` : ""}</td><td><div class="row-actions"><button class="mini-btn" data-edit-material="${m.id}">Sửa</button><button class="mini-btn" data-delete-material="${m.id}">Xoá</button></div></td></tr>`).join("")}</tbody></table></div>`; }
function renderChannels() { $("#channelsView").innerHTML = `${pageHeading("KÊNH BÁN & PHÍ", "Profile bán hàng", "Tạo nhiều profile cho Facebook/Zalo, Shopee, TikTok Shop, cộng tác viên, khách sỉ hay đại lý.", `<button class="primary-button" data-add-profile>＋ Thêm profile</button>`)}<div class="product-grid">${state.salesProfiles.map(profile => { const anyProduct = state.products.find(p => p.salesProfileId === profile.id) || state.products[0]; const calc = anyProduct ? productionAndPricing(anyProduct, resolveSalesSettings(anyProduct, profile)) : null; return `<article class="product-card"><div class="product-card-body"><div class="product-card-top"><span class="product-index">${escapeHtml(profile.name)}</span><div><button class="card-menu" data-edit-profile="${profile.id}">Sửa</button><button class="card-menu" data-delete-profile="${profile.id}" title="Xoá profile">⌫</button></div></div><h3>${escapeHtml(profile.name)}</h3><p>${escapeHtml(profile.note || "Chưa có ghi chú")}</p><div class="card-stats"><div><strong>${money(profile.fixedFeeVnd)}</strong><span>Phí cố định</span></div><div><strong>${number(profile.variableFeeRate)}%</strong><span>Phí tỷ lệ</span></div></div><div class="card-stats"><div><strong>${money(profile.minimumProfitVnd)}</strong><span>Lợi nhuận tối thiểu</span></div><div><strong>${number(profile.targetMarginRate)}%</strong><span>Margin mục tiêu</span></div></div>${calc ? `<div class="profile-mini">${money(calc.roundedSafePrice || 0)} · giá an toàn mẫu đầu</div>` : ""}</div></article>`; }).join("")}<article class="product-card new-card" data-add-profile><div><b>＋</b><h3>Tạo profile</h3><p>Thiết lập phí cho một kênh bán</p></div></article></div>`; }
function renderMembers() { const owner = currentMember?.role === "owner"; $("#membersView").innerHTML = `${pageHeading("WORKSPACE CHUNG", "Thành viên xưởng", `Mọi người đăng nhập Google riêng và cùng làm trên “${escapeHtml(activeWorkspace?.name || "Xưởng")}”.`, owner ? `<span class="workspace-role">Bạn là chủ xưởng</span>` : `<span class="workspace-role">Quyền ${currentMember?.role === "viewer" ? "chỉ xem" : "chỉnh sửa"}</span>`)}<div class="members-layout"><section class="panel"><div class="panel-head"><h3>${workspaceMembers.length} thành viên</h3><span class="member-hint">Dữ liệu cập nhật cho tất cả tài khoản</span></div><div class="member-list">${workspaceMembers.map(m => memberRow(m)).join("")}</div></section><aside class="invite-card ${owner ? "" : "disabled"}"><span class="eyebrow">MỜI VÀO XƯỞNG</span><h2>${owner ? "Thêm người nhà" : "Chỉ chủ xưởng được mời"}</h2><p>${owner ? "Nhập đúng email Google của người nhận, rồi gửi link được tạo." : "Nhờ chủ workspace tạo link mời thành viên mới."}</p>${owner ? `<form id="inviteForm"><label>Email Google<input id="inviteEmail" type="email" required placeholder="vo-ban@gmail.com"></label><label>Quyền truy cập<select id="inviteRole"><option value="editor">Được chỉnh sửa</option><option value="viewer">Chỉ xem</option></select></label><button class="primary-button" type="submit">Tạo link mời</button></form><div id="inviteResult" class="invite-result" hidden><span>Link dùng cho đúng email vừa nhập</span><div><input id="inviteLinkOutput" readonly><button id="copyInviteBtn" class="secondary-button" data-copy-target="#inviteLinkOutput">Sao chép</button></div></div>` : ""}</aside></div>`; }
function memberRow(member) { const role = { owner: "Chủ xưởng", editor: "Chỉnh sửa", viewer: "Chỉ xem" }[member.role] || member.role; return `<div class="member-row"><span class="member-avatar">${member.photoURL ? `<img src="${escapeAttr(member.photoURL)}" alt="">` : escapeHtml((member.displayName || member.email || "?").slice(0, 1).toUpperCase())}</span><div><strong>${escapeHtml(member.displayName || "Thành viên")}${member.id === currentUser?.uid ? " · Bạn" : ""}</strong><small>${escapeHtml(member.email || "")}</small></div><span class="member-role ${member.role}">${role}</span></div>`; }
function createInvite(email, role) { if (currentMember?.role !== "owner") throw new Error("workspace/no-access"); const token = (crypto.randomUUID() + crypto.randomUUID()).replaceAll("-", "").slice(0, 40); return setDoc(doc(db, "invites", token), { workspaceId: activeWorkspaceId, workspaceName: activeWorkspace?.name || "Xưởng gia đình", email: email.trim().toLowerCase(), role, createdBy: currentUser.uid, createdAt: serverTimestamp() }).then(() => `${location.origin}${location.pathname}?invite=${token}`); }
function openMaterialDialog(id) { const m = state.materials.find(x => x.id === id); $("#materialDialogTitle").textContent = m ? "Chỉnh vật tư" : "Thêm vật tư"; $("#materialId").value = m?.id || ""; $("#materialName").value = m?.name || ""; $("#materialCategory").value = m?.category || inferMaterialCategory(m?.name || ""); $("#materialCost").value = m?.cost ?? ""; $("#materialQuantity").value = m?.quantity ?? ""; $("#materialUnit").value = m?.unit || ""; $("#materialSupplier").value = m?.supplier || ""; $("#materialLastPurchasedAt").value = m?.lastPurchasedAt || ""; $("#materialMinStock").value = m?.minStock ?? 0; $("#materialNote").value = m?.note || ""; $("#materialAppliesPrintWaste").checked = m?.appliesPrintWaste ?? (m?.category === "print_material"); $("#materialAppliesMachineCosts").checked = m?.appliesMachineCosts ?? (m?.category === "print_material"); updateUnitPreview(); $("#materialDialog").showModal(); }
function openProfileDialog(id) { const p = state.salesProfiles.find(x => x.id === id); $("#profileDialogTitle").textContent = p ? "Chỉnh profile" : "Thêm profile"; $("#profileId").value = p?.id || ""; $("#profileName").value = p?.name || ""; $("#profileNote").value = p?.note || ""; $("#profileRoundingStep").value = p?.roundingStep || 1000; $("#profileFixedFee").value = p?.fixedFeeVnd || 0; $("#profileVariableFeeRate").value = p?.variableFeeRate || 0; $("#profileShippingSupport").value = p?.shippingSupportVnd || 0; $("#profileVoucherPercent").value = p?.voucherPercent || 0; $("#profileVoucherFixed").value = p?.voucherFixedVnd || 0; $("#profileReturnReserveRate").value = p?.returnReserveRate || 0; $("#profileAffiliateRate").value = p?.affiliateRate || 0; $("#profileAdsVnd").value = p?.adsCostVnd || 0; $("#profileTaxRate").value = p?.taxRate || 0; $("#profileTargetMarginRate").value = p?.targetMarginRate || 0; $("#profileMinimumProfitVnd").value = p?.minimumProfitVnd || 0; $("#profileDialog").showModal(); }
function updateUnitPreview() { const c = num($("#materialCost").value); const q = Math.max(0.0001, num($("#materialQuantity").value, 1)); $("#unitPricePreview").textContent = money(c / q); }
function deleteMaterial(id) { const m = state.materials.find(x => x.id === id); const usage = state.products.reduce((n, p) => n + p.components.filter(c => c.materialId === id).length, 0); confirm(`Xoá “${m?.name || ""}”?`, usage ? `Vật tư này đang được dùng ở ${usage} cấu phần. Các dòng đó sẽ được giữ lại nhưng không còn đơn giá.` : "Thao tác này không thể hoàn tác.", () => { state.materials = state.materials.filter(x => x.id !== id); saveState(); renderMaterials(); toast("Đã xoá vật tư"); }); }
function deleteProfile(id) { if (state.salesProfiles.length <= 1) { toast("Cần giữ ít nhất một profile"); return; } confirm("Xoá profile?", "Các sản phẩm đang dùng profile này sẽ tự chuyển sang profile đầu tiên.", () => { state.salesProfiles = state.salesProfiles.filter(p => p.id !== id); const fallback = state.salesProfiles[0]?.id; state.products.forEach(p => { if (p.salesProfileId === id) p.salesProfileId = fallback; }); saveState(); renderChannels(); toast("Đã xoá profile"); }); }
function confirm(title, message, cb) { $("#confirmTitle").textContent = title; $("#confirmMessage").textContent = message; confirmCallback = cb; $("#confirmDialog").showModal(); }
function bomRow(product, component) { const materials = state.materials.map(m => `<option value="${m.id}" ${m.id === component.materialId ? "selected" : ""}>${escapeHtml(m.name)} · ${money(unitPrice(m))}/${escapeHtml(m.unit.toLowerCase())}</option>`).join(""); return `<div class="bom-row" data-component-id="${component.id}"><input class="component-input" data-field="name" value="${escapeAttr(component.name)}" placeholder="Tên cấu phần"/><select data-field="materialId">${materials}</select><input data-field="quantity" type="number" min="0" step="0.1" value="${component.quantity}" title="Lượng vật tư dùng"/><input data-field="printHours" type="number" min="0" step="0.1" value="${component.printHours || 0}" title="Số giờ máy"/><span class="bom-cost">${money(componentCost(component))}</span><button class="delete-row" data-remove-component title="Xoá dòng">×</button></div>`; }

document.addEventListener("click", e => { if (e.target.closest("#loginGoogleBtn")) { handleAuthClick(); return; } if (e.target.closest("#authBtn")) { handleAuthClick(); return; } const copyButton = e.target.closest("[data-copy-target]"); if (copyButton) { const field = $(copyButton.dataset.copyTarget); copyText(field?.value || field?.textContent || ""); return; } const nav = e.target.closest("[data-view]"); if (nav) { navigate(nav.dataset.view); return; } const go = e.target.closest("[data-go]"); if (go) { navigate(go.dataset.go); return; } const product = e.target.closest("[data-product-id]"); if (product && !e.target.closest("[data-duplicate]")) { navigate("editor", product.dataset.productId); return; } if (e.target.closest("[data-create-product]") || e.target.closest("#quickAddBtn")) { createProduct(); return; } const duplicate = e.target.closest("[data-duplicate]"); if (duplicate) { e.stopPropagation(); duplicateProduct(duplicate.dataset.duplicate); return; } if (e.target.closest("[data-back-products]")) { navigate("products"); return; } const delProduct = e.target.closest("[data-delete-product]"); if (delProduct) { const p = state.products.find(x => x.id === delProduct.dataset.deleteProduct); confirm(`Xoá “${p?.name || ""}”?`, "Toàn bộ định mức của mẫu này sẽ bị xoá.", () => { state.products = state.products.filter(x => x.id !== p.id); removeCloudImage(p.id); saveState(); navigate("products"); toast("Đã xoá mẫu"); }); return; } if (e.target.closest("[data-add-component]")) { const p = state.products.find(x => x.id === currentProductId); p.components.push({ id: uid(), name: "Cấu phần mới", materialId: state.materials[0]?.id || "", quantity: 1, printHours: 0 }); saveState(); renderEditor(); return; } const remove = e.target.closest("[data-remove-component]"); if (remove) { const p = state.products.find(x => x.id === currentProductId); const row = remove.closest(".bom-row"); p.components = p.components.filter(c => c.id !== row.dataset.componentId); saveState(); renderEditor(); return; } if (e.target.closest("[data-remove-image]")) { const p = state.products.find(x => x.id === currentProductId); p.image = ""; removeCloudImage(p.id); saveState(); renderEditor(); toast("Đã xoá ảnh sản phẩm"); return; } if (e.target.closest("[data-add-material]")) { openMaterialDialog(); return; } if (e.target.closest("[data-add-profile]")) { openProfileDialog(); return; } const edit = e.target.closest("[data-edit-material]"); if (edit) { openMaterialDialog(edit.dataset.editMaterial); return; } const del = e.target.closest("[data-delete-material]"); if (del) { deleteMaterial(del.dataset.deleteMaterial); return; } const editProfile = e.target.closest("[data-edit-profile]"); if (editProfile) { openProfileDialog(editProfile.dataset.editProfile); return; } const delProfile = e.target.closest("[data-delete-profile]"); if (delProfile) { deleteProfile(delProfile.dataset.deleteProfile); return; } if (e.target.closest("[data-close-dialog]")) { e.target.closest("dialog").close(); return; } if (e.target.closest("#menuBtn")) { $(".sidebar").classList.toggle("open"); return; } });
document.addEventListener("submit", async e => { if (e.target.id === "inviteForm") { e.preventDefault(); const button = e.target.querySelector('button[type="submit"]'); button.disabled = true; button.textContent = "Đang tạo…"; try { const link = await createInvite($("#inviteEmail").value, $("#inviteRole").value); $("#inviteLinkOutput").value = link; $("#inviteResult").hidden = false; button.textContent = "Tạo link khác"; } catch (error) { console.error(error); toast(firebaseErrorMessage(error)); button.textContent = "Tạo link mời"; } button.disabled = false; return; } if (e.target.id === "materialForm") { e.preventDefault(); const id = $("#materialId").value; const data = normalizeMaterial({ id: id || uid(), name: $("#materialName").value.trim(), category: $("#materialCategory").value, cost: num($("#materialCost").value), quantity: num($("#materialQuantity").value), unit: $("#materialUnit").value.trim(), supplier: $("#materialSupplier").value.trim(), lastPurchasedAt: $("#materialLastPurchasedAt").value, minStock: num($("#materialMinStock").value), note: $("#materialNote").value.trim(), appliesPrintWaste: $("#materialAppliesPrintWaste").checked, appliesMachineCosts: $("#materialAppliesMachineCosts").checked }); const i = state.materials.findIndex(m => m.id === id); if (i >= 0) state.materials[i] = data; else state.materials.push(data); saveState(); $("#materialDialog").close(); renderMaterials(); toast(id ? "Đã cập nhật vật tư" : "Đã thêm vật tư"); return; } if (e.target.id === "profileForm") { e.preventDefault(); const id = $("#profileId").value; const data = normalizeProfile({ id: id || uid(), name: $("#profileName").value.trim(), note: $("#profileNote").value.trim(), roundingStep: num($("#profileRoundingStep").value, 1000), fixedFeeVnd: num($("#profileFixedFee").value), variableFeeRate: num($("#profileVariableFeeRate").value), shippingSupportVnd: num($("#profileShippingSupport").value), voucherPercent: num($("#profileVoucherPercent").value), voucherFixedVnd: num($("#profileVoucherFixed").value), returnReserveRate: num($("#profileReturnReserveRate").value), affiliateRate: num($("#profileAffiliateRate").value), adsCostVnd: num($("#profileAdsVnd").value), taxRate: num($("#profileTaxRate").value), targetMarginRate: num($("#profileTargetMarginRate").value), minimumProfitVnd: num($("#profileMinimumProfitVnd").value) }); const i = state.salesProfiles.findIndex(p => p.id === id); if (i >= 0) state.salesProfiles[i] = data; else state.salesProfiles.push(data); state.products.forEach(p => { if (!p.salesProfileId) p.salesProfileId = data.id; }); saveState(); $("#profileDialog").close(); renderChannels(); if (currentView === "editor") renderEditor(); toast(id ? "Đã cập nhật profile" : "Đã thêm profile"); } });
document.addEventListener("input", e => { if (e.target.id === "productSearch") { renderProducts(e.target.value); $("#productSearch").focus(); return; } if (e.target.id === "materialSearch") { renderMaterials(e.target.value); $("#materialSearch").focus(); return; } if (e.target.id === "materialCost" || e.target.id === "materialQuantity") { updateUnitPreview(); return; } const p = state.products.find(x => x.id === currentProductId); if (!p) return; if (e.target.id === "productName") { const oldName = p.name; p.name = e.target.value; if (!p.listing.title || p.listing.title === oldName) { p.listing.title = e.target.value; const titleCopy = $("#copyListingTitle"); if (titleCopy) titleCopy.value = e.target.value; } saveState(); return; } if (e.target.id === "roundingInput") { p.rounding = Math.max(1, num(e.target.value, 1)); rememberTemplateDefaults(p); saveState(); renderEditor(); return; } if (e.target.id === "targetPriceInput") { p.targetPrice = num(e.target.value); saveState(); renderEditor(); return; } if (e.target.id === "saleListingPrice") { p.saleScenario.listingPrice = num(e.target.value); saveState(); renderEditor(); return; } if (e.target.id === "saleVoucherPercent") { p.saleScenario.voucherPercent = e.target.value === "" ? null : num(e.target.value); saveState(); renderEditor(); return; } if (e.target.id === "saleVoucherFixedVnd") { p.saleScenario.voucherFixedVnd = e.target.value === "" ? null : num(e.target.value); saveState(); renderEditor(); return; } if (e.target.id === "productSalesProfileId") { p.salesProfileId = e.target.value; rememberTemplateDefaults(p); saveState(); renderEditor(); return; } if (e.target.dataset.costField) { p.costing[e.target.dataset.costField] = num(e.target.value); rememberTemplateDefaults(p); saveState(); renderEditor(); return; } if (e.target.dataset.batchField) { p.batch[e.target.dataset.batchField] = num(e.target.value); saveState(); renderEditor(); return; } if (e.target.dataset.salesOverride) { p.salesOverrides[e.target.dataset.salesOverride] = e.target.value === "" ? "" : num(e.target.value); saveState(); renderEditor(); return; } if (e.target.dataset.listingField) { p.listing[e.target.dataset.listingField] = e.target.value; saveState(); return; } const row = e.target.closest(".bom-row"); if (row && e.target.dataset.field) { const c = p.components.find(x => x.id === row.dataset.componentId); const field = e.target.dataset.field; c[field] = ["quantity", "printHours"].includes(field) ? num(e.target.value) : e.target.value; saveState(); renderEditor(); } });
document.addEventListener("change", async e => { if (e.target.id === "productImageInput" && e.target.files?.[0]) { const file = e.target.files[0]; if (!file.type.startsWith("image/")) { toast("Vui lòng chọn file ảnh"); return; } try { const p = state.products.find(x => x.id === currentProductId); p.image = await compressImage(file); saveState(); await syncImage(p.id, p.image); renderEditor(); toast("Đã thêm ảnh sản phẩm"); } catch { toast("Không thể đọc ảnh này"); } return; } });
$("#confirmDialog").addEventListener("close", () => { if ($("#confirmDialog").returnValue === "confirm" && confirmCallback) confirmCallback(); confirmCallback = null; });
$("#exportBtn").addEventListener("click", () => { const blob = new Blob([JSON.stringify(state, null, 2)], { type: "application/json" }); const a = document.createElement("a"); a.href = URL.createObjectURL(blob); a.download = `xuong-nho-du-lieu-${new Date().toISOString().slice(0, 10)}.json`; a.click(); URL.revokeObjectURL(a.href); toast("Đã xuất bản sao dữ liệu"); });
$("#importInput").addEventListener("change", async e => { try { const data = JSON.parse(await e.target.files[0].text()); state = normalizeState(data); saveState(); if (currentUser && cloudReady) for (const p of state.products) if (p.image) await syncImage(p.id, p.image); navigate("dashboard"); toast("Đã nhập dữ liệu"); } catch { toast("File dữ liệu không hợp lệ"); } e.target.value = ""; });
async function handleAuthClick() { if (location.protocol === "file:") { toast("Đăng nhập cloud cần mở qua GitHub Pages hoặc localhost"); return; } try { if (currentUser && $("#appShell").classList.contains("is-hidden")) await bootstrapWorkspace(currentUser); else if (currentUser) await signOut(auth); else await signInWithPopup(auth, googleProvider); } catch (error) { console.error(error); toast(firebaseErrorMessage(error)); } }

updatePills(); navigate("dashboard"); showLogin(); if (inviteTokenFromUrl) $("#inviteNotice").hidden = false; onAuthStateChanged(auth, async user => { currentUser = user; if (user) { showLoginLoading("Đang xác thực tài khoản…"); await bootstrapWorkspace(user); } else { cloudReady = false; activeWorkspaceId = null; activeWorkspace = null; currentMember = null; workspaceMembers = []; clearTimeout(syncTimer); showLogin(); } });
